using System;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;
using System.ComponentModel.DataAnnotations;

namespace EventBookingSystem
{
    public class Event
    {
        public int Id { get; set; }
        public int TotalSeats { get; set; }
        public int SoldSeats { get; set; }
        public int AvailableSeats => TotalSeats - SoldSeats;
        
        [Timestamp]
        public byte[] RowVersion { get; set; }
    }

    public class BookingContext : DbContext
    {
        public DbSet<Event> Events { get; set; }
        public BookingContext(DbContextOptions<BookingContext> options) : base(options)
        {
        }
    }

    public class TicketService
    {
        private readonly BookingContext _context;
        public TicketService(BookingContext context)
        {
            _context = context;
        }
        
        public async Task<bool> PurchaseTicketsAsync(int eventId, int purchaseQuantity)
        {
            const int maxRetry = 3;
            for (int retry = 0; retry < maxRetry; retry++)
            {
                using (var transaction = await _context.Database.BeginTransactionAsync())
                {
                    try
                    {
                        var eventRecord = await _context.Events
                            .Where(e => e.Id == eventId)
                            .FirstOrDefaultAsync();

                        if (eventRecord == null)
                        {
                            // Event not found
                            return false;
                        }
                        
                        if (purchaseQuantity <= 0)
                        {
                            // Invalid purchase quantity
                            return false;
                        }
                        
                        if (eventRecord.AvailableSeats < purchaseQuantity)
                        {
                            // Not enough seats available
                            return false;
                        }
                        
                        eventRecord.SoldSeats += purchaseQuantity;
                        await _context.SaveChangesAsync();
                        await transaction.CommitAsync();
                        return true;
                    }
                    catch (DbUpdateConcurrencyException)
                    {
                        await transaction.RollbackAsync();
                        if (retry == maxRetry - 1)
                        {
                            // Maximum retries reached, rethrow exception
                            throw;
                        }
                        // Wait briefly before retrying
                        await Task.Delay(50);
                    }
                    catch (Exception)
                    {
                        await transaction.RollbackAsync();
                        throw;
                    }
                }
            }
            return false;
        }
    }
}